          PushNotificationChannel.postMessage(JSON.stringify({action: 'unsubscribe', topic: topic}));
        },
        
        // General native functions
        showToast: function(message) {
          NativeChannel.postMessage(JSON.stringify({action: 'showToast', message: message}));
        },
        hapticFeedback: function(type) {
          NativeChannel.postMessage(JSON.stringify({action: 'hapticFeedback', type: type || 'medium'}));
        },
        openSettings: function() {
          NativeChannel.postMessage(JSON.stringify({action: 'openSettings'}));
        },
        getLocation: function() {
          NativeChannel.postMessage(JSON.stringify({action: 'getLocation'}));
        },
